package genxsolution.vms.vmsbackend.maintenance_management.vehicle_filter_type.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.maintenance_management.vehicle_filter_type.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.vehicle_filter_type.service.VehicleFilterTypeService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/vehicle-filter-types") public class VehicleFilterTypeController { private final VehicleFilterTypeService service; public VehicleFilterTypeController(VehicleFilterTypeService service){this.service=service;} @GetMapping public List<VehicleFilterTypeResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public VehicleFilterTypeResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public VehicleFilterTypeResponse create(@RequestBody VehicleFilterTypeUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public VehicleFilterTypeResponse update(@PathVariable UUID id,@RequestBody VehicleFilterTypeUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
